    private static void safePad4(StringBuffer buffer, int value) {
        // This method is only called with positive values (absolute values of negative years)
        // so we can safely use the original logic without worrying about negative handling
        int h = value / 100;
        if (h == 0) {
            buffer.append('0').append('0');
        } else {
            safePad2(buffer, h);
            value -= (100 * h);
        }
        safePad2(buffer, value);
